export function extractImportSpecifiers(source) {
  const pattern = /(?:import\s+[^"']*from\s+|import\s*\()\s*["']([^"']+)["']/g;
  const rows = [];
  let match = pattern.exec(source ?? "");
  while (match) {
    rows.push(match[1]);
    match = pattern.exec(source ?? "");
  }
  return rows;
}

